const codes = {"Java": "<span class=\"kw\">class</span> <span class=\"cl\">RangeIterator</span> <span class=\"kw\">implements</span> <span class=\"cl\">Iterator</span>&lt;<span class=\"cl\">Integer</span>&gt; {\n  <span class=\"kw\">private int</span> <span class=\"dc\">cur</span>, <span class=\"dc\">end</span>;\n\n  <span class=\"fn\">RangeIterator</span>(<span class=\"kw\">int</span> <span class=\"dc\">start</span>, <span class=\"kw\">int</span> <span class=\"dc\">end</span>) {\n    <span class=\"dc\">this</span>.<span class=\"dc\">cur</span> = <span class=\"dc\">start</span>; <span class=\"dc\">this</span>.<span class=\"dc\">end</span> = <span class=\"dc\">end</span>;\n  }\n\n  <span class=\"kw\">public boolean</span> <span class=\"fn\">hasNext</span>() { <span class=\"kw\">return</span> <span class=\"dc\">cur</span> &lt; <span class=\"dc\">end</span>; }\n  <span class=\"kw\">public</span> <span class=\"cl\">Integer</span> <span class=\"fn\">next</span>()    { <span class=\"kw\">return</span> <span class=\"dc\">cur</span>++; }\n}\n\n<span class=\"cm\">// Iterator<Integer> it = new RangeIterator(1, 6);</span>\n<span class=\"cm\">// while (it.hasNext()) System.out.println(it.next()); // 1 2 3 4 5</span>", "CSharp": "<span class=\"kw\">public class</span> <span class=\"cl\">RangeIterator</span>(<span class=\"kw\">int</span> <span class=\"dc\">start</span>, <span class=\"kw\">int</span> <span class=\"dc\">end</span>)\n    : <span class=\"cl\">IEnumerable</span>&lt;<span class=\"kw\">int</span>&gt; {\n\n  <span class=\"kw\">public</span> <span class=\"cl\">IEnumerator</span>&lt;<span class=\"kw\">int</span>&gt; <span class=\"fn\">GetEnumerator</span>() {\n    <span class=\"kw\">for</span> (<span class=\"kw\">int</span> <span class=\"dc\">i</span> = <span class=\"dc\">start</span>; <span class=\"dc\">i</span> &lt; <span class=\"dc\">end</span>; <span class=\"dc\">i</span>++)\n      <span class=\"kw\">yield return</span> <span class=\"dc\">i</span>;\n  }\n\n  <span class=\"cl\">IEnumerator</span> <span class=\"cl\">IEnumerable</span>.<span class=\"fn\">GetEnumerator</span>() =&gt; <span class=\"fn\">GetEnumerator</span>();\n}\n\n<span class=\"kw\">foreach</span> (<span class=\"kw\">var</span> <span class=\"dc\">n</span> <span class=\"kw\">in</span> <span class=\"kw\">new</span> <span class=\"cl\">RangeIterator</span>(1, 6))\n  <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"dc\">n</span>); <span class=\"cm\">// 1 2 3 4 5</span>", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">RangeIterator</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">start</span>, <span class=\"dc\">end</span>):\n    <span class=\"dc\">self.cur</span>, <span class=\"dc\">self.end</span> = <span class=\"dc\">start</span>, <span class=\"dc\">end</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">__iter__</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return self</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">__next__</span>(<span class=\"dc\">self</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">self.cur</span> >= <span class=\"dc\">self.end</span>: <span class=\"kw\">raise</span> <span class=\"cl\">StopIteration</span>\n    <span class=\"dc\">v</span> = <span class=\"dc\">self.cur</span>; <span class=\"dc\">self.cur</span> += 1; <span class=\"kw\">return</span> <span class=\"dc\">v</span>\n\n\n<span class=\"kw\">for</span> <span class=\"dc\">n</span> <span class=\"kw\">in</span> <span class=\"cl\">RangeIterator</span>(1, 6):\n  <span class=\"fn\">print</span>(<span class=\"dc\">n</span>)  <span class=\"cm\"># 1 2 3 4 5</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">RangeIterator</span>\n  <span class=\"kw\">include</span> <span class=\"cl\">Enumerable</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>(<span class=\"dc\">s</span>, <span class=\"dc\">e</span>) = <span class=\"dc\">@r</span> = (<span class=\"dc\">s</span>...<span class=\"dc\">e</span>)\n  <span class=\"kw\">def</span> <span class=\"fn\">each</span>(&<span class=\"dc\">b</span>) = <span class=\"dc\">@r</span>.<span class=\"fn\">each</span>(&<span class=\"dc\">b</span>)\n<span class=\"kw\">end</span>\n\n<span class=\"cl\">RangeIterator</span>.<span class=\"fn\">new</span>(1, 6).<span class=\"fn\">each</span> { |<span class=\"dc\">n</span>| <span class=\"fn\">puts</span> <span class=\"dc\">n</span> }"}

